Example quick option — Three.js house scene:
```html
<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8" />
  <title>3D House</title>
  <style>body{margin:0}canvas{display:block}</style>
</head>
<body>
<script type="module">
import * as THREE from 'https://unpkg.com/three@0.160.0/build/three.module.js';
import { OrbitControls } from 'https://unpkg.com/three@0.160.0/examples/jsm/controls/OrbitControls.js';

const scene = new THREE.Scene();
scene.background = new THREE.Color(0xbfd1e5);

const camera = new THREE.PerspectiveCamera(60, innerWidth / innerHeight, 0.1, 1000);
camera.position.set(6, 5, 8);

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(innerWidth, innerHeight);
document.body.appendChild(renderer.domElement);

const controls = new OrbitControls(camera, renderer.domElement);

const light = new THREE.DirectionalLight(0xffffff, 1.2);
light.position.set(5, 10, 7);
scene.add(light);
scene.add(new THREE.AmbientLight(0xffffff, 0.6));

const ground = new THREE.Mesh(
  new THREE.PlaneGeometry(30, 30),
  new THREE.MeshStandardMaterial({ color: 0x88aa88 })
);
ground.rotation.x = -Math.PI / 2;
scene.add(ground);

const houseBody = new THREE.Mesh(
  new THREE.BoxGeometry(4, 3, 4),
  new THREE.MeshStandardMaterial({ color: 0xd9c2a3 })
);
houseBody.position.y = 1.5;
scene.add(houseBody);

const roof = new THREE.Mesh(
  new THREE.ConeGeometry(3.3, 2, 4),
  new THREE.MeshStandardMaterial({ color: 0x8b2e2e })
);
roof.position.y = 4;
roof.rotation.y = Math.PI / 4;
scene.add(roof);

const door = new THREE.Mesh(
  new THREE.BoxGeometry(0.8, 1.6, 0.1),
  new THREE.MeshStandardMaterial({ color: 0x654321 })
);
door.position.set(0, 0.8, 2.05);
scene.add(door);

function makeWindow(x, y, z) {
  const w = new THREE.Mesh(
    new THREE.BoxGeometry(0.9, 0.9, 0.1),
    new THREE.MeshStandardMaterial({ color: 0x99ccff })
  );
  w.position.set(x, y, z);
  scene.add(w);
}
makeWindow(-1.2, 1.8, 2.05);
makeWindow(1.2, 1.8, 2.05);

addEventListener('resize', () => {
  camera.aspect = innerWidth / innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth, innerHeight);
});

function animate() {
  requestAnimationFrame(animate);
  controls.update();
  renderer.render(scene, camera);
}
animate();
</script>
</body>
</html>
```

